import{_ as d,o as e,c as o,ag as c}from"./chunks/framework.DlJzNSsD.js";const u=JSON.parse('{"title":"Keybindings","description":"","frontmatter":{},"headers":[],"relativePath":"reference/keybindings.md","filePath":"reference/keybindings.md","lastUpdated":1778758826000}'),a={name:"reference/keybindings.md"};function r(n,t,i,s,h,l){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="keybindings" tabindex="-1">Keybindings <a class="header-anchor" href="#keybindings" aria-label="Permalink to &quot;Keybindings&quot;">​</a></h1><p>Every keybinding shipped with Clawterm, grouped by category. The <strong>Mod</strong> column shows the primary modifier for your platform: <code>Cmd</code> on macOS, <code>Ctrl</code> on Windows and Linux.</p><p>All bindings marked <strong>configurable</strong> can be remapped in <code>config.json</code> under the <code>keybindings</code> block — see <a href="./configuration#keybindings">configuration.md</a>. Hardcoded bindings cannot be changed.</p><p>Source of truth: <a href="../../src/config.ts"><code>src/config.ts</code></a> (defaults) and <a href="../../src/keybinding-handler.ts"><code>src/keybinding-handler.ts</code></a> (dispatch logic).</p><h2 id="tabs" tabindex="-1">Tabs <a class="header-anchor" href="#tabs" aria-label="Permalink to &quot;Tabs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>New tab</td><td><code>Mod+T</code></td><td><code>newTab</code></td><td></td></tr><tr><td>Close active tab</td><td><code>Mod+W</code></td><td><code>closeTab</code></td><td></td></tr><tr><td>Restore last closed tab</td><td><code>Mod+Shift+T</code></td><td><code>restoreTab</code></td><td></td></tr><tr><td>Next tab</td><td><code>Mod+Shift+]</code></td><td><code>nextTab</code></td><td></td></tr><tr><td>Previous tab</td><td><code>Mod+Shift+[</code></td><td><code>prevTab</code></td><td></td></tr><tr><td>Next tab (alt)</td><td><code>Mod+↓</code></td><td>—</td><td>Hardcoded</td></tr><tr><td>Previous tab (alt)</td><td><code>Mod+↑</code></td><td>—</td><td>Hardcoded</td></tr><tr><td>Switch to tab 1–9</td><td><code>Mod+1</code> … <code>Mod+9</code></td><td>—</td><td>Hardcoded</td></tr><tr><td>Quick tab switcher</td><td><code>Mod+P</code></td><td><code>quickSwitch</code></td><td>Fuzzy-find across tabs</td></tr><tr><td>Cycle tabs needing attention</td><td><code>Mod+Shift+A</code></td><td><code>cycleAttention</code></td><td>Jumps between tabs whose agent is waiting</td></tr></tbody></table><h2 id="split-panes" tabindex="-1">Split panes <a class="header-anchor" href="#split-panes" aria-label="Permalink to &quot;Split panes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>Split horizontally</td><td><code>Mod+D</code></td><td><code>splitHorizontal</code></td><td></td></tr><tr><td>Split vertically</td><td><code>Mod+Shift+D</code></td><td><code>splitVertical</code></td><td></td></tr><tr><td>Close active pane</td><td><code>Mod+Shift+W</code></td><td><code>closePane</code></td><td></td></tr><tr><td>Focus next pane</td><td><code>Mod+]</code></td><td><code>focusNextPane</code></td><td></td></tr><tr><td>Focus previous pane</td><td><code>Mod+[</code></td><td><code>focusPrevPane</code></td><td></td></tr><tr><td>Focus pane 1–9</td><td><code>Mod+Alt+1</code> … <code>Mod+Alt+9</code></td><td>—</td><td>Hardcoded</td></tr><tr><td>Resize pane</td><td><code>Mod+Shift+←↑→↓</code></td><td>—</td><td>Hardcoded</td></tr></tbody></table><h2 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>Next project</td><td><code>Mod+Alt+]</code></td><td><code>nextProject</code></td><td></td></tr><tr><td>Previous project</td><td><code>Mod+Alt+[</code></td><td><code>prevProject</code></td><td></td></tr><tr><td>New project</td><td><em>(unbound)</em></td><td><code>newProject</code></td><td>Set in <code>config.json</code> to enable</td></tr></tbody></table><h2 id="worktrees" tabindex="-1">Worktrees <a class="header-anchor" href="#worktrees" aria-label="Permalink to &quot;Worktrees&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>New worktree tab</td><td><code>Mod+Shift+N</code></td><td><code>newWorktreeTab</code></td><td>Opens the worktree dialog</td></tr><tr><td>Toggle workspace panel</td><td><code>Mod+Shift+B</code></td><td><code>toggleWorkspacePanel</code></td><td></td></tr><tr><td>Jump to branch</td><td><code>Mod+Shift+G</code></td><td><code>jumpToBranch</code></td><td></td></tr></tbody></table><h2 id="search-and-palette" tabindex="-1">Search and palette <a class="header-anchor" href="#search-and-palette" aria-label="Permalink to &quot;Search and palette&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>Toggle in-terminal search</td><td><code>Mod+F</code></td><td><code>search</code></td><td></td></tr><tr><td>Command palette</td><td><code>Mod+Shift+P</code></td><td><code>commandPalette</code></td><td>All actions, fuzzy-searchable</td></tr><tr><td>Open settings</td><td><code>Cmd+,</code></td><td>—</td><td>Hardcoded, <strong>macOS only</strong></td></tr></tbody></table><h2 id="zoom" tabindex="-1">Zoom <a class="header-anchor" href="#zoom" aria-label="Permalink to &quot;Zoom&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>Zoom in</td><td><code>Mod+=</code></td><td><code>zoomIn</code></td><td>Also matches <code>Mod+Shift+=</code> / <code>Mod++</code></td></tr><tr><td>Zoom out</td><td><code>Mod+-</code></td><td><code>zoomOut</code></td><td></td></tr><tr><td>Reset zoom</td><td><code>Mod+0</code></td><td><code>zoomReset</code></td><td></td></tr></tbody></table><h2 id="miscellaneous" tabindex="-1">Miscellaneous <a class="header-anchor" href="#miscellaneous" aria-label="Permalink to &quot;Miscellaneous&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Default</th><th>Config key</th><th>Notes</th></tr></thead><tbody><tr><td>Reload config</td><td><code>Mod+Shift+R</code></td><td><code>reloadConfig</code></td><td>Picks up edits to <code>config.json</code> without restarting</td></tr></tbody></table><h2 id="quick-commands" tabindex="-1">Quick commands <a class="header-anchor" href="#quick-commands" aria-label="Permalink to &quot;Quick commands&quot;">​</a></h2><p>Quick commands are user-defined keybindings that <strong>type a string into the active pane</strong> instead of triggering an action. They live in <code>config.json</code> under <code>quickCommands</code> as <code>{ &quot;binding&quot;: &quot;text to type&quot; }</code> pairs.</p><table tabindex="0"><thead><tr><th>Default binding</th><th>Text typed</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Mod+Shift+C</code></td><td><code>claude --dangerously-skip-permissions\\n</code></td><td>Launch Claude Code with permission prompts suppressed</td></tr></tbody></table><p>See <a href="./configuration#quickcommands">configuration.md</a> for the full format and more examples.</p><h2 id="binding-format" tabindex="-1">Binding format <a class="header-anchor" href="#binding-format" aria-label="Permalink to &quot;Binding format&quot;">​</a></h2><p>Keybindings are strings of the form <code>modifier+modifier+key</code>, lowercase, joined with <code>+</code>:</p><ul><li><strong>Modifiers:</strong> <code>cmd</code>, <code>ctrl</code>, <code>shift</code>, <code>alt</code> (<code>opt</code> is accepted as an alias for <code>alt</code>)</li><li><strong>Keys:</strong> single characters (<code>a</code>–<code>z</code>, <code>0</code>–<code>9</code>), punctuation (<code>[</code>, <code>]</code>, <code>=</code>, <code>-</code>, <code>,</code>, <code>.</code>, <code>/</code>, <code>;</code>, <code>&#39;</code>, <code>`</code>, <code>\\</code>), or arrow keys</li><li><code>cmd</code> maps to the Meta key (⌘ on macOS); <code>ctrl</code> maps to Control. They are treated as <strong>distinct</strong> modifiers, so a binding that uses <code>cmd</code> will not fire on a <code>Ctrl</code> press.</li></ul><p>Shifted punctuation is handled automatically: a binding of <code>cmd+=</code> also matches <code>Cmd+Shift+=</code> (which produces <code>+</code> on most layouts).</p><p>Invalid keybinding strings are logged and reset to the default for that action.</p>',27)])])}const f=d(a,[["render",r]]);export{u as __pageData,f as default};
